class Solution {
public:
    int getMaxRepetitions(string s1, int n1, string s2, int n2) {
        int len1 = s1.size(), len2 = s2.size();
        vector<int> repeatCount(len2 + 1, 0);
        vector<int> nextIndex(len2 + 1, 0);
        int j = 0, count = 0;
        for (int k = 0; k < n1; ++k) {
            for (int i = 0; i < len1; ++i) {
                if (s1[i] == s2[j]) {
                    ++j;
                    if (j == len2) {
                        j = 0;
                        ++count;
                    }
                }
            }
            repeatCount[k] = count;
            nextIndex[k] = j;
            for (int start = 0; start < k; ++start) {
                if (nextIndex[start] == j) {
                    int interval = k - start;
                    int repeat = (n1 - 1 - start) / interval;
                    count = repeatCount[start] + repeat * (repeatCount[k] - repeatCount[start]);
                    int remaining = start + (n1 - 1 - start) % interval;
                    count = repeatCount[remaining] + (count - repeatCount[start]);
                    return count / n2;
                }
            }
        }
        return count / n2;
    }
};
